const items = $input.all();

const courses = items.filter(item => {
  // Skip site-level course (id=1)
  if (item.json.id === 1) return false;
  return true;
});

return courses.map(item => ({ json: item.json }));

const SUPPORTED_MIMES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  'text/markdown'
];

// Get course info from the Loop Courses node
const courseItem = $('Loop Courses').item;
const courseId = courseItem.json.id;
const rawShortname = courseItem.json.shortname || `course-${courseId}`;
const namespace = rawShortname.toLowerCase().replace(/\s+/g, '-');

const response = $input.first();
const sections = response.json.body || response.json;

const files = [];

if (!Array.isArray(sections)) {
  // API returned an error or unexpected format
  return [{ json: { error: 'Unexpected response format', courseId, namespace, files: [] } }];
}

for (const section of sections) {
  if (!section.modules) continue;
  for (const mod of section.modules) {
    if (!mod.contents) continue;
    for (const content of mod.contents) {
      if (content.type !== 'file') continue;
      if (!SUPPORTED_MIMES.includes(content.mimetype)) continue;

      // Prefix filename with module ID to avoid collisions across sections
      const uniqueFilename = `mod${mod.id}_${content.filename}`;

      files.push({
        fileurl: content.fileurl,
        filename: content.filename,
        uniqueFilename: uniqueFilename,
        filesize: content.filesize,
        timemodified: content.timemodified,
        mimetype: content.mimetype,
        moduleId: mod.id,
        moduleName: mod.name,
        sectionName: section.name,
        courseId: courseId,
        namespace: namespace
      });
    }
  }
}

return [{ json: { courseId, namespace, files } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.courseFiles) {
  staticData.courseFiles = {};
}

const input = $input.first().json;
const namespace = input.namespace;
const courseId = input.courseId;
const currentFiles = input.files || [];

const storedFiles = staticData.courseFiles[namespace] || {};

const toIngest = [];    // new or updated files
const toDelete = [];    // removed files
const unchanged = [];   // no change

// Build set of current file URLs for removal detection
const currentFileUrls = new Set(currentFiles.map(f => f.fileurl));

// Check each current file against stored state
for (const file of currentFiles) {
  const stored = storedFiles[file.fileurl];
  if (!stored) {
    // New file
    toIngest.push({ ...file, action: 'new' });
  } else if (stored.timemodified !== file.timemodified) {
    // Updated file
    toIngest.push({ ...file, action: 'updated', old_document_id: stored.document_id });
  } else {
    unchanged.push({ ...file, action: 'unchanged' });
  }
}

// Check for removed files (in state but not in current contents)
for (const [fileurl, stored] of Object.entries(storedFiles)) {
  if (!currentFileUrls.has(fileurl)) {
    toDelete.push({
      fileurl,
      filename: stored.filename,
      document_id: stored.document_id,
      namespace,
      action: 'removed'
    });
  }
}

return [{
  json: {
    courseId,
    namespace,
    toIngest,
    toDelete,
    unchanged,
    summary: {
      new: toIngest.filter(f => f.action === 'new').length,
      updated: toIngest.filter(f => f.action === 'updated').length,
      removed: toDelete.length,
      unchanged: unchanged.length
    }
  }
}];

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const namespace = input.namespace;
const toDelete = input.toDelete || [];

const results = [];

for (const file of toDelete) {
  if (file.document_id) {
    results.push({
      json: {
        document_id: file.document_id,
        namespace: file.namespace || namespace,
        filename: file.filename,
        fileurl: file.fileurl
      }
    });
  }

  // Remove from state
  if (staticData.courseFiles && staticData.courseFiles[namespace]) {
    delete staticData.courseFiles[namespace][file.fileurl];
  }
}

if (results.length === 0) {
  return [{ json: { message: 'No documents to delete', namespace } }];
}

return results;

// Process all files for this course: download from Moodle, upload to Vektra
const input = $('Dedup & Diff').item.json;
const toIngest = input.toIngest || [];
const namespace = input.namespace;
const courseId = input.courseId;

const MOODLE_WS_TOKEN = $env.MOODLE_WS_TOKEN;
const VEKTRA_API_URL = $env.VEKTRA_API_URL;
const VEKTRA_API_KEY = $env.VEKTRA_API_KEY;
const authHeader = { Authorization: `Bearer ${VEKTRA_API_KEY}` };

const staticData = $getWorkflowStaticData('global');
if (!staticData.courseFiles) staticData.courseFiles = {};
if (!staticData.courseFiles[namespace]) staticData.courseFiles[namespace] = {};

const results = [];

for (const file of toIngest) {
  const uniqueFilename = `mod${file.moduleId}_${file.filename}`;
  try {
    // Step 1: If updated file, delete old version first
    if (file.action === 'updated' && file.old_document_id) {
      await this.helpers.httpRequest({
        method: 'DELETE',
        url: `${VEKTRA_API_URL}/api/v1/documents/batch`,
        body: { document_ids: [file.old_document_id], namespace },
        headers: { 'Content-Type': 'application/json', ...authHeader },
      });
    }

    // Step 2: Download file from Moodle
    const separator = file.fileurl.includes('?') ? '&' : '?';
    const downloadUrl = `${file.fileurl}${separator}token=${MOODLE_WS_TOKEN}`;
    const fileBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: downloadUrl,
      encoding: 'arraybuffer',
      returnFullResponse: true,
    });

    const contentType = fileBuffer.headers?.['content-type'] || '';
    if (contentType.includes('application/json')) {
      const errorBody = Buffer.from(fileBuffer.body).toString();
      results.push({ file_name: uniqueFilename, namespace, courseId, action: file.action, status: 'failed', document_id: null, chunk_count: 0, error: 'Download failed: ' + errorBody.substring(0, 100) });
      continue;
    }

    // Step 3: Upload to Vektra (manual multipart/form-data)
    const boundary = '----n8nBoundary' + Date.now();
    const fileData = Buffer.from(fileBuffer.body);
    const header = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${uniqueFilename}"\r\nContent-Type: ${file.mimetype}\r\n\r\n`;
    const footer = `\r\n--${boundary}--\r\n`;
    const multipartBody = Buffer.concat([Buffer.from(header), fileData, Buffer.from(footer)]);

    const ingestResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: `${VEKTRA_API_URL}/api/v1/ingest?namespace=${encodeURIComponent(namespace)}`,
      body: multipartBody,
      headers: { 'Content-Type': `multipart/form-data; boundary=${boundary}`, ...authHeader },
      returnFullResponse: true,
    });

    const statusCode = ingestResponse.statusCode;
    const body = typeof ingestResponse.body === 'string' ? JSON.parse(ingestResponse.body) : ingestResponse.body;
    const documentId = body.document_id || null;
    const rawStatus = body.status || (statusCode >= 200 && statusCode < 300 ? 'completed' : 'failed');
    const status = (['new', 'exists', 'alias'].includes(rawStatus) && documentId) ? 'completed' : rawStatus;
    const chunkCount = body.chunk_count || 0;
    const error = body.detail?.error?.message || body.error?.message || null;

    // Step 4: Handle async (202) — poll for completion
    if (statusCode === 202 && body.job_id) {
      let pollStatus = 'processing';
      let pollCount = 0;
      while (pollStatus === 'processing' && pollCount < 60) {
        await new Promise(resolve => setTimeout(resolve, 5000));
        const pollResp = await this.helpers.httpRequest({
          method: 'GET',
          url: `${VEKTRA_API_URL}/api/v1/ingest/jobs/${body.job_id}/status`,
          headers: authHeader,
          returnFullResponse: true,
        });
        const pollBody = typeof pollResp.body === 'string' ? JSON.parse(pollResp.body) : pollResp.body;
        pollStatus = pollBody.status;
        pollCount++;
      }
    }

    // Step 5: Update state
    if (documentId && status === 'completed') {
      staticData.courseFiles[namespace][file.fileurl] = {
        timemodified: file.timemodified,
        document_id: documentId,
        filename: uniqueFilename,
        last_synced: new Date().toISOString()
      };
    }

    results.push({ file_name: uniqueFilename, namespace, courseId, action: file.action, status, document_id: documentId, chunk_count: chunkCount, error });
  } catch (e) {
    results.push({ file_name: uniqueFilename, namespace, courseId, action: file.action, status: 'failed', document_id: null, chunk_count: 0, error: e.message?.substring(0, 200) });
  }
}

return [{ json: { courseResults: results, resultCount: results.length } }];

// Merge results from all courses
// Each input item has { courseResults: [...] } from Aggregate Results
const items = $input.all();

let totalNew = 0;
let totalUpdated = 0;
let totalRemoved = 0;
let totalUnchanged = 0;
let totalFailed = 0;
const details = [];

for (const item of items) {
  const results = item.json.courseResults || [item.json];
  for (const d of results) {
    if (d.action === 'new' && (d.status === 'completed' || d.status === 'new')) totalNew++;
    else if (d.action === 'updated' && (d.status === 'completed' || d.status === 'new')) totalUpdated++;
    else if (d.action === 'removed') totalRemoved++;
    else if (d.action === 'unchanged' || d.status === 'skipped') totalUnchanged++;
    else if (d.status === 'failed' || d.status === 'timeout') totalFailed++;

    if (d.file_name || d.filename) {
      details.push({
        file: d.file_name || d.filename,
        namespace: d.namespace,
        action: d.action || 'unknown',
        status: d.status || 'n/a',
        document_id: d.document_id || null,
        error: d.error || null
      });
    }
  }
}

const summary = `Sync complete: ${totalNew} new, ${totalUpdated} updated, ${totalRemoved} removed, ${totalUnchanged} unchanged, ${totalFailed} failed`;

console.log(summary);

return [{
  json: {
    summary,
    totals: { new: totalNew, updated: totalUpdated, removed: totalRemoved, unchanged: totalUnchanged, failed: totalFailed },
    details
  }
}];

// No files to ingest for this course — return single aggregated item
const input = $('Dedup & Diff').item.json;
const unchangedFiles = (input.unchanged || []).map(f => ({
  file_name: f.uniqueFilename || f.filename,
  namespace: input.namespace,
  courseId: input.courseId,
  action: 'unchanged',
  status: 'skipped'
}));

return [{ json: { courseResults: unchangedFiles, resultCount: unchangedFiles.length } }];
